import React, { useEffect, useState } from 'react';
import axios from 'axios';

const InventoryList = () => {
    const [inventory, setInventory] = useState([]);

    useEffect(() => {
        axios.get('http://localhost:5000/api/inventory')
            .then(response => setInventory(response.data))
            .catch(error => console.error(error));
    }, []);

    return (
        <div className="container mx-auto p-4">
            <h1 className="text-3xl font-bold mb-4">Inventory Management</h1>
            <div className="overflow-x-auto">
                <table className="min-w-full bg-white border border-gray-300">
                    <thead>
                        <tr className="bg-gray-100">
                            <th className="py-2 px-4 border">Inventory ID</th>
                            <th className="py-2 px-4 border">Item Type</th>
                            <th className="py-2 px-4 border">Brand</th>
                            <th className="py-2 px-4 border">Model</th>
                            <th className="py-2 px-4 border">Qty</th>
                            <th className="py-2 px-4 border">Status</th>
                            <th className="py-2 px-4 border">Details</th>
                        </tr>
                    </thead>
                    <tbody>
                        {inventory.map(item => (
                            <tr key={item.id} className="hover:bg-gray-50">
                                <td className="py-2 px-4 border">{item.inventory_id}</td>
                                <td className="py-2 px-4 border">{item.item_type}</td>
                                <td className="py-2 px-4 border">{item.brand}</td>
                                <td className="py-2 px-4 border">{item.model}</td>
                                <td className="py-2 px-4 border">{item.qty}</td>
                                <td className="py-2 px-4 border">{item.status}</td>
                                <td className="py-2 px-4 border">{item.details}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default InventoryList;
